from flask import request
import xml.etree.ElementTree as ET
import re

tree = ET.parse('users.xml')
root = tree.getroot()

@app.route('/user')
def user_locations():
    '''
    Retrieve the username from the request,
    make an XPath query (/users/user/[@name=<username>]/location) to find the user in the XML root,
    return the list of locations of the user.
    '''
    username = request.args.get('username', '')
    # Sanitize input to prevent XPath injection: only allow alphanumeric and underscore
    if not re.match(r'^[a-zA-Z0-9_]+$', username):
        return [], 400  # Invalid username format

    locations = []
    for user in root.findall('user'):
        if user.get('name') == username:
            for location in user.findall('location'):
                if location.text:
                    locations.append(location.text)
    return locations
